                "title": {
                    "zh_hk": "選讀西班牙文的原因",
                    "zh_mo": "選讀西班牙文的原因",
                    "zh_tw": "選讀西班牙文的原因",
                    "en": "Purpose of learning Spanish"
                },
                "options": [
                    {
                        "zh_hk": "工作需要",
                        "zh_mo": "工作需要",
                        "zh_tw": "工作需要",
                        "en": "Job-related"
                    },
                    {
                        "zh_hk": "學業考試",
                        "zh_mo": "學業考試",
                        "zh_tw": "學業考試",
                        "en": "Academic"
                    },
                    {
                        "zh_hk": "出國或移民",
                        "zh_mo": "出國或移民",
                        "zh_tw": "出國或移民",
                        "en": "Relocation"
                    },
                    {
                        "zh_hk": "興趣",
                        "zh_mo": "興趣",
                        "zh_tw": "興趣",
                        "en": "Own Interest"
                    }
                ]
            }
        ]';

        $questions = json_decode($questions, true);

        $questionValues = [];
        $questionTranslations = [];
        $questionOptionValues = [];
        $questionOptionTranslations = [];

        $optionId = 1;

        foreach ($questions as $id => $question) {
            $questionValues[] = [
                'category' => $question['category'],
                'type' => $question['type'],
                'is_addable' => $question['is_addable'],
                'is_custom' => $question['is_custom'],
                'created_at' => $now,
                'updated_at' => $now
            ];

            $questionTranslations[$id + 1] = $question['title'];

            foreach ($question['options'] as $option) {
                $questionOptionValues[] = ['question_id' => $id + 1];
                $questionOptionTranslations[$optionId] = $option;
                $optionId++;
            }
        }

        $questionGroups = [
            ['name' => '共通', 'created_at' => $now, 'updated_at' => $now],
            ['name' => '清潔', 'created_at' => $now, 'updated_at' => $now],
            ['name' => '健身', 'created_at' => $now, 'updated_at' => $now],
            ['name' => '球類運動', 'created_at' => $now, 'updated_at' => $now],
            ['name' => '音樂', 'created_at' => $now, 'updated_at' => $now],
        ];

        $questionGroupQuestions = [
            ['question_group_id' => 1, 'question_id' => 1],
            ['question_group_id' => 3, 'question_id' => 1],
            ['question_group_id' => 3, 'question_id' => 2],
            ['question_group_id' => 5, 'question_id' => 1],
            ['question_group_id' => 5, 'question_id' => 2],
            ['question_group_id' => 5, 'question_id' => 3]
        ];

        DB::table('questions')->insert($questionValues);
        DB::table('question_options')->insert($questionOptionValues);
        DB::table('question_groups')->insert($questionGroups);
        DB::table('question_group_questions')->insert($questionGroupQuestions);
        DB::table('translations')->insert([
            'table' => 'questions',
            'column' => 'title',
            'translation' => json_encode($questionTranslations, JSON_UNESCAPED_UNICODE)
        ]);
        DB::table('translations')->insert([
            'table' => 'question_options',
            'column' => 'name',
            'translation' => json_encode($questionOptionTranslations, JSON_UNESCAPED_UNICODE)
        ]);
    }
}
